"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { getSupabaseBrowserClient } from "@/lib/supabase/browser-client";

export default function LoginPage() {
  const r = useRouter();
  const supabase = getSupabaseBrowserClient();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [err, setErr] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    setErr(null);
    setLoading(true);

    const { error } = await supabase.auth.signInWithPassword({ email, password });

    setLoading(false);

    if (error) {
      setErr(error.message);
      return;
    }

    r.push("/dashboard");
    r.refresh();
  }

  return (
    <main className="min-h-screen bg-[#0b0b0c] text-[#D9D9D9] grid place-items-center px-6">
      <form
        onSubmit={onSubmit}
        className="w-full max-w-sm rounded-2xl border border-white/10 bg-white/5 p-6"
      >
        <div className="text-2xl font-bold">Login</div>
        <div className="mt-1 text-sm text-[#D9D9D9]/60">
          Dev login (temporary)
        </div>

        <div className="mt-5 space-y-3">
          <input
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="email"
            className="w-full rounded-xl border border-white/10 bg-black/30 px-4 py-3 text-sm text-[#D9D9D9] placeholder:text-[#D9D9D9]/40 outline-none"
          />
          <input
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="password"
            type="password"
            className="w-full rounded-xl border border-white/10 bg-black/30 px-4 py-3 text-sm text-[#D9D9D9] placeholder:text-[#D9D9D9]/40 outline-none"
          />

          {err ? (
            <div className="text-sm text-[#D9D9D9]/70">
              <span className="text-[#8B000D]">Error:</span> {err}
            </div>
          ) : null}

          <button
            type="submit"
            disabled={loading}
            className="w-full rounded-full border border-white/10 bg-[#8B000D] px-4 py-3 text-sm text-white hover:brightness-110 transition disabled:opacity-60"
          >
            {loading ? "Signing in..." : "Sign in"}
          </button>

          <a
            href="/"
            className="block text-center text-xs text-[#D9D9D9]/60 hover:text-[#D9D9D9]/80"
          >
            Back
          </a>
        </div>
      </form>
    </main>
  );
}